34	/// Report a clang error diagnostic. Note that the message must be a string
35	/// literal. \p astNode is a node from the clang AST with source location
36	/// information.
37	template <typename T, unsigned N>
38	void reportClangError(T *astNode, clang::DiagnosticsEngine &de,
39	                      const char (&msg)[N]) {
40	  auto id = de.getCustomDiagID(clang::DiagnosticsEngine::Error, msg);
41	  de.Report(astNode->getBeginLoc(), id);
42	}
43	template <typename T, unsigned N>
44	void reportClangError(T *astNode, clang::ItaniumMangleContext *mangler,
45	                      const char (&msg)[N]) {
46	  reportClangError(astNode, mangler->getASTContext().getDiagnostics(), msg);
47	}
