49	/// `measure_handle` arrives at the bridge as either an SSA `!cc.measure_handle`
50	/// or as the pointer form `!cc.ptr<!cc.measure_handle>` left by lvalue access
51	/// (named variable read, `operator=` LHS, struct-member-of-handle, ...). Most
52	/// consumers want the value form, so funnel that normalization through one
53	/// helper rather than open-coding the `dyn_cast` chain at every call site.
54	inline mlir::Value loadHandleIfPointer(mlir::OpBuilder &builder,
55	                                       mlir::Location loc, mlir::Value v) {
56	  if (auto ptrTy = mlir::dyn_cast<cudaq::cc::PointerType>(v.getType()))
57	    if (mlir::isa<cudaq::cc::MeasureHandleType>(ptrTy.getElementType()))
58	      return cudaq::cc::LoadOp::create(builder, loc, v);
59	  return v;
60	}
61	
62	/// Same intent as `loadHandleIfPointer`, but for the bulk-discriminate /
63	/// `to_integer` / range-for / qec.{detector,observable,pair_detectors} paths
64	/// where the lvalue carries a `std::vector<measure_handle>` and `ConvertDecl`
65	/// has stack-allocated a descriptor slot for it.
66	inline mlir::Value loadHandleVectorIfPointer(mlir::OpBuilder &builder,
67	                                             mlir::Location loc,
68	                                             mlir::Value v) {
69	  if (auto ptrTy = mlir::dyn_cast<cudaq::cc::PointerType>(v.getType()))
70	    if (auto sv = mlir::dyn_cast<cudaq::cc::StdvecType>(ptrTy.getElementType());
71	        sv && mlir::isa<cudaq::cc::MeasureHandleType>(sv.getElementType()))
72	      return cudaq::cc::LoadOp::create(builder, loc, v);
73	  return v;
74	}
