156	/// QuakeBridgeVisitor is a visitor pattern for crawling over the AST and
157	/// generating Quake, CC, and other MLIR dialects.
158	///
159	/// The general design is to walk the tree in a post-order traversal and
160	/// assemble the IR from the leaves back down the tree. Traversals over types
161	/// should push Type values to the type stack. Traversals over expressions
162	/// should create IR in the ModuleOp as well as push subexpressions on the
163	/// stack for parent nodes. A parent node always knows how many children it
164	/// needs to be constructed correctly. The types of expressions are carried
165	/// along with the expressions in the IR and need not be duplicated on the type
166	/// stack.
167	///
168	/// Unfortunately, clang's RecursiveASTVisitor doesn't always visit nodes in the
169	/// AST and can skip visiting types or even some expressions.
170	class QuakeBridgeVisitor
171	    : public clang::RecursiveASTVisitor<QuakeBridgeVisitor> {
172	  using Base = clang::RecursiveASTVisitor<QuakeBridgeVisitor>;
173	
174	public:
175	  explicit QuakeBridgeVisitor(
176	      clang::ASTContext *astCtx, mlir::MLIRContext *mlirCtx,
177	      mlir::OpBuilder &bldr, mlir::ModuleOp module, SymbolTable &symTab,
178	      EmittedFunctionsCollection &funcsToEmit,
179	      llvm::ArrayRef<clang::Decl *> reachableFuncs,
180	      MangledKernelNamesMap &namesMap, clang::CompilerInstance &ci,
181	      clang::ItaniumMangleContext *mangler,
182	      std::unordered_map<std::string, std::string> &customOperations,
183	      llvm::BumpPtrAllocator &alloc, bool tuplesAreReversed)
184	      : astContext(astCtx), mlirContext(mlirCtx), builder(bldr), module(module),
185	        symbolTable(symTab), functionsToEmit(funcsToEmit),
186	        reachableFunctions(reachableFuncs), namesMap(namesMap),
187	        compilerInstance(ci), mangler(mangler),
188	        customOperationNames(customOperations), allocator(alloc),
189	        tuplesAreReversed(tuplesAreReversed) {}
190	
191	  /// `nvq++` renames quantum kernels to differentiate them from classical C++
192	  /// code. This renaming is done on function names. \p tag makes it easier
193	  /// to identify the kernel class from which the function was extracted.
194	  std::string generateCudaqKernelName(const clang::FunctionDecl *func) {
195	    return getCudaqKernelName(
196	        cudaq::detail::getTagNameOfFunctionDecl(func, mangler));
197	  }
198	  std::string generateCudaqKernelName(const EmittedFunctionPair &emittedFunc) {
199	    if (emittedFunc.first.starts_with(runtime::cudaqGenPrefixName))
200	      return emittedFunc.first;
201	    return generateCudaqKernelName(emittedFunc.second);
202	  }
