713	/// The ASTBridgeAction enables the insertion of a custom ASTConsumer to the
714	/// Clang AST analysis / processing workflow. The nested ASTBridgeConsumer
715	/// drives the process of walking the Clang AST and translate pertinent nodes to
716	/// an MLIR Op tree containing Quake, CC, and other MLIR dialect operations.
717	/// In short, this Action generates the MLIR Module.
718	class ASTBridgeAction : public clang::ASTFrontendAction {
719	public:
720	  using MangledKernelNamesMap = cudaq::MangledKernelNamesMap;
