746	
747	    // The MLIR Module we are building up
748	    mlir::OwningOpRef<mlir::ModuleOp> &module;
749	
750	    // Observed quantum functions, we will iterate through these in buildMLIR()
751	    EmittedFunctionsCollection functionsToEmit;
752	    clang::CallGraph callGraphBuilder;
753	
