814	/// Return true if and only if \p x was declared at the top-level.
815	inline bool isNotInANamespace(const clang::Decl *x) {
816	  assert(x && "decl is null");
817	  auto *declCtx = x->getDeclContext();
818	  do {
819	    if (isa<clang::NamespaceDecl>(declCtx))
820	      return false;
821	    declCtx = declCtx->getParent();
822	  } while (declCtx);
823	  return true;
824	}
825	
826	/// Return true if and only if \p x was declared in the namespace \p nsName.
827	/// This test will "drill through" any nested namespaces in search of a match.
828	inline bool isInNamespace(const clang::Decl *x, mlir::StringRef nsName) {
829	  assert(x && "decl is null");
830	  auto *declCtx = x->getDeclContext();
831	  do {
832	    if (const auto *nsd = dyn_cast<clang::NamespaceDecl>(declCtx))
833	      if (const auto *nsi = nsd->getIdentifier())
834	        if (nsi->getName() == nsName)
835	          return true;
836	    declCtx = declCtx->getParent();
837	  } while (declCtx);
838	  return false;
839	}
840	
841	/// Return true if and only if \p x was declared in the class \p className and
842	/// that class was furthermore declared in the namespace \p nsName.
843	inline bool isInClassInNamespace(const clang::Decl *x,
844	                                 mlir::StringRef className,
845	                                 mlir::StringRef nsName) {
846	  assert(x && "decl is null");
847	  if (const auto *cld = dyn_cast<clang::RecordDecl>(x->getDeclContext()))
848	    if (const auto *cli = cld->getIdentifier())
849	      return (cli->getName() == className) && isInNamespace(cld, nsName);
850	  return false;
851	}
