860	/// Is \p t of type `char *`?
861	inline bool isCharPointerType(mlir::Type t) {
862	  if (auto ptrTy = dyn_cast<cc::PointerType>(t)) {
863	    mlir::Type eleTy = ptrTy.getElementType();
864	    if (auto arrTy = dyn_cast<cc::ArrayType>(eleTy))
865	      eleTy = arrTy.getElementType();
866	    if (auto intTy = dyn_cast<mlir::IntegerType>(eleTy))
867	      return intTy.getWidth() == 8;
868	  }
869	  return false;
870	}
