873	inline bool isCharspanPointerType(mlir::Type t) {
874	  if (auto ptrTy = dyn_cast<cc::PointerType>(t)) {
875	    mlir::Type eleTy = ptrTy.getElementType();
876	    return isa<cc::CharspanType>(eleTy);
877	  }
878	  return false;
879	}
