  //===--------------------------------------------------------------------===//
  // Type traversals
  //===--------------------------------------------------------------------===//

  bool pushType(mlir::Type t);
  mlir::Type popType();
  mlir::Type peekType() { return typeStack.back(); }

  /// Return the last `n` types from the stack in left-to-right (natural)
