37	// Generate a list (as a vector) of all the reachable functions recorded in the
38	// call graph, \p cgn.
39	static llvm::SmallVector<clang::Decl *>
40	listReachableFunctions(clang::CallGraphNode *cgn) {
41	  llvm::SmallVector<clang::Decl *> result;
42	  for (auto call : *cgn) {
43	    auto *decl = call.Callee->getDecl();
44	    if (auto *nd = dyn_cast<clang::NamedDecl>(decl)) {
45	      LLVM_DEBUG(llvm::dbgs() << "adding function: "
46	                              << nd->getQualifiedNameAsString() << '\n');
47	    }
48	    result.push_back(decl);
49	  }
50	  return result;
51	}
