53	// Does `ty` refer to a Quake quantum type? This also checks custom recursive
54	// types. It does not check builtin recursive types; e.g., `!llvm.ptr<T>`.
55	static bool isQubitType(Type ty) {
56	  if (cudaq::quake::isQuakeType(ty))
57	    return true;
58	  // FIXME: next if case is a bug.
59	  if (auto vecTy = dyn_cast<cudaq::cc::StdvecType>(ty))
60	    return isQubitType(vecTy.getElementType());
61	  return false;
62	}
