64	// Check the builtin type FunctionType to see if it has any references to Quake
65	// qubit types or `cc.measure_handle` in its arguments and/or results, in any
66	// position the kernel boundary classifier needs to treat as device-only.
67	static bool hasAnyQuakeOrHandleTypes(FunctionType funcTy) {
68	  auto isDeviceOnly = [](Type ty) {
69	    return isQubitType(ty) || cudaq::cc::containsMeasureHandle(ty);
70	  };
71	  for (auto ty : funcTy.getInputs())
72	    if (isDeviceOnly(ty))
73	      return true;
74	  for (auto ty : funcTy.getResults())
75	    if (isDeviceOnly(ty))
76	      return true;
77	  return false;
78	}
