80	// Like `hasAnyQuakeOrHandleTypes`, but only the handle component. Used by the
81	// functor-`operator()` diagnostic, which fires only when the signature carries
82	// a handle (free `__qpu__` functions silently demote even when they carry
83	// qubit references).
84	static bool containsHandleInSignature(FunctionType funcTy) {
85	  for (auto ty : funcTy.getInputs())
86	    if (cudaq::cc::containsMeasureHandle(ty))
87	      return true;
88	  for (auto ty : funcTy.getResults())
89	    if (cudaq::cc::containsMeasureHandle(ty))
90	      return true;
