94	// Remove the Itanium mangling "_ZTS" prefix. This is to match the name returned
95	// by `typeid(TYPE).name()`.
96	static std::string
97	trimmedMangledTypeName(clang::QualType ty,
98	                       clang::ItaniumMangleContext *mangler) {
99	  auto s = cudaq::detail::getCxxMangledTypeName(ty, mangler);
100	  // Strip off the prefix.
101	  constexpr char prefix[] = "_ZTS";
102	  constexpr auto prefixLength = sizeof(prefix) - 1;
103	  assert(s.length() > prefixLength);
104	  if (s.substr(0, prefixLength) == prefix)
105	    s = s.substr(prefixLength);
106	  // Strip off any leading length. (Similar to original scheme.)
107	  while (std::isdigit(s[0]))
108	    s = s.substr(1);
109	  return s;
110	}
