112	std::string
113	cudaq::detail::getTagNameOfFunctionDecl(const clang::FunctionDecl *func,
114	                                        clang::ItaniumMangleContext *mangler) {
115	  if (auto *cxxMethod = dyn_cast<clang::CXXMethodDecl>(func)) {
116	    auto *cxxCls = cast<clang::CXXRecordDecl>(func->getParent());
117	    if (cxxMethod->isFunctionTemplateSpecialization()) {
118	      // Template member function.
119	      // class C {
120	      //   template<typename A> T operator()(args...) { ... }
121	      // };
122	      // cudaq::get_class_kernel_name<C, As...>();
123	      auto name =
124	          "instance_" +
125	          trimmedMangledTypeName(
126	              mangler->getASTContext().getCanonicalTagType(cxxCls), mangler);
127	      assert(cxxMethod->getTemplateSpecializationArgs());
128	      for (auto &templArg :
129	           cxxMethod->getTemplateSpecializationArgs()->asArray())
130	        name += trimmedMangledTypeName(templArg.getAsType(), mangler);
131	      name += '.' + cudaq::detail::getCxxMangledDeclName(func, mangler);
132	      LLVM_DEBUG(llvm::dbgs() << "template member name is: " << name << '\n');
133	      return name;
134	    }
135	    // Member function, but not a template function.
136	    // cudaq::get_class_kernel_name<C>();
137	    auto name = trimmedMangledTypeName(
138	        mangler->getASTContext().getCanonicalTagType(cxxCls), mangler);
139	    LLVM_DEBUG(llvm::dbgs() << "member name is: " << name << '\n');
140	    return name;
141	  }
142	  if (func->isTemplateInstantiation()) {
143	    // Template function.
144	    // template<typename A> __qpu__ T func(args ...);
145	    // cudaq::get_function_kernel_name<As...>("func");
146	    auto name = "instance_function_" + func->getName().str();
147	    for (auto templArg : func->getTemplateSpecializationArgs()->asArray())
148	      name += trimmedMangledTypeName(templArg.getAsType(), mangler);
149	    name += '.' + cudaq::detail::getCxxMangledDeclName(func, mangler);
150	    LLVM_DEBUG(llvm::dbgs() << "template function name is: " << name << '\n');
151	    return name;
152	  }
153	  // Plain, old function.
154	  // __qpu__ T func(args ...);
155	  // cudaq::get_function_kernel_name("func");
156	  auto name = "function_" + func->getName().str();
157	  name += '.' + cudaq::detail::getCxxMangledDeclName(func, mangler);
158	  LLVM_DEBUG(llvm::dbgs() << "function name is: " << name << '\n');
159	  return name;
160	}
