163	/// The QPU code finder class is used to find all function definitions that the
164	/// user has annotated with a QPU attribute (`__qpu__`). The finder is a simple
165	/// visitor that traverses declarations as called from the AST consumer.
166	class QPUCodeFinder : public clang::RecursiveASTVisitor<QPUCodeFinder> {
167	public:
168	  using Base = clang::RecursiveASTVisitor<QPUCodeFinder>;
169	  explicit QPUCodeFinder(
170	      cudaq::EmittedFunctionsCollection &funcsToEmit, clang::CallGraph &cgb,
171	      clang::ItaniumMangleContext *mangler, ModuleOp module,
172	      std::unordered_map<std::string, std::string> &customOperations)
173	      : functionsToEmit(funcsToEmit), callGraphBuilder(cgb), mangler(mangler),
174	        module(module), customOperationNames(customOperations) {}
175	
176	  /// Add a kernel to the list of kernels to process.
177	  template <bool replace = true>
178	  void processQpu(const std::string &kernelName, const clang::FunctionDecl *f) {
179	    LLVM_DEBUG(llvm::dbgs()
180	               << "adding kernel: " << kernelName << ", "
181	               << reinterpret_cast<void *>(const_cast<clang::FunctionDecl *>(f))
182	               << '\n');
183	    auto iter = std::find_if(functionsToEmit.begin(), functionsToEmit.end(),
184	                             [&](auto p) { return p.first == kernelName; });
185	    if constexpr (replace) {
186	      if (iter == functionsToEmit.end())
187	        functionsToEmit.push_back(std::make_pair(kernelName, f));
188	      else
189	        iter->second = f;
190	      callGraphBuilder.addToCallGraph(const_cast<clang::FunctionDecl *>(f));
191	    } else {
192	      if (iter == functionsToEmit.end())
193	        functionsToEmit.push_back(std::make_pair(kernelName, f));
194	    }
195	  }
196	
197	  // Check some of the restrictions and limitations on kernel classes. These
198	  // restrictions are noted in the CUDA-Q language specification.
199	  void check(const clang::CXXRecordDecl *x) {
200	    if (!checkedClass)
201	      return;
202	
203	    auto &de = mangler->getASTContext().getDiagnostics();
204	    if (!x->bases().empty()) {
205	      auto id = de.getCustomDiagID(
206	          clang::DiagnosticsEngine::Error,
207	          "class inheritance is not allowed for CUDA-Q kernel");
208	      de.Report(x->getBeginLoc(), id);
209	    }
210	    if (!x->fields().empty()) {
211	      auto id = de.getCustomDiagID(
212	          clang::DiagnosticsEngine::Error,
213	          "CUDA-Q kernel class with data members is not yet supported");
214	      de.Report(x->getBeginLoc(), id);
215	    }
216	    unsigned quantumCount = 0;
217	    for (auto *method : x->methods()) {
218	      if (cudaq::ASTBridgeAction::ASTBridgeConsumer::isQuantum(method)) {
219	        if (quantumCount++) {
220	          auto id = de.getCustomDiagID(clang::DiagnosticsEngine::Error,
221	                                       "CUDA-Q kernel class with multiple "
222	                                       "quantum methods not yet supported");
223	          de.Report(method->getBeginLoc(), id);
224	          break;
225	        }
226	      }
227	    }
228	    checkedClass = nullptr;
229	  }
230	
231	  bool TraverseCXXRecordDecl(clang::CXXRecordDecl *x) {
232	    // Keep track of which CXXRecordDecl is being visited for semantics
233	    // checking.
234	    auto *savedCheckedClass = checkedClass;
235	    checkedClass = x;
236	    bool result = Base::TraverseCXXRecordDecl(x);
237	    checkedClass = savedCheckedClass;
238	    return result;
239	  }
240	
241	  bool TraverseFunctionDecl(clang::FunctionDecl *x) {
242	    // Do not allow non-kernel functions to use quantum data types.
243	    bool saveQuantumTypesNotAllowed = quantumTypesNotAllowed;
244	    auto result = Base::TraverseFunctionDecl(x);
245	    quantumTypesNotAllowed = saveQuantumTypesNotAllowed;
246	    return result;
247	  }
248	
249	  bool VisitFunctionDecl(clang::FunctionDecl *x) {
250	    if (ignoreTemplate)
251	      return true;
252	    auto *func = x->getDefinition();
253	
254	    if (func) {
255	      bool runChecks = false;
256	      if (cudaq::ASTBridgeAction::ASTBridgeConsumer::isCustomOpGenerator(
257	              func)) {
258	        customOperationNames[func->getName().str()] =
259	            cudaq::detail::getTagNameOfFunctionDecl(func, mangler);
260	        runChecks = true;
261	      }
262	      if (cudaq::ASTBridgeAction::ASTBridgeConsumer::isQuantum(func))
263	        runChecks = true;
264	      else
265	        quantumTypesNotAllowed = true;
266	
267	      if (runChecks) {
268	        quantumTypesNotAllowed = false;
269	        // Run semantics checks on the kernel class.
270	        if (isa<clang::CXXMethodDecl>(func)) {
271	          auto *cxxClass = cast<clang::CXXRecordDecl>(func->getParent());
272	          check(cxxClass);
273	        }
274	        processQpu(cudaq::detail::getTagNameOfFunctionDecl(func, mangler),
275	                   func);
276	      }
277	    } else if (cudaq::ASTBridgeAction::ASTBridgeConsumer::isQuantum(x)) {
278	      // Add declarations to support separate compilation.
279	      processQpu</*replace=*/false>(
280	          cudaq::detail::getTagNameOfFunctionDecl(x, mangler), x);
281	    }
282	    return true;
283	  }
284	
285	  // NB: DataRecursionQueue* argument intentionally omitted.
286	  bool TraverseLambdaExpr(clang::LambdaExpr *x) {
287	    bool saveQuantumTypesNotAllowed = quantumTypesNotAllowed;
288	    // Rationale: a lambda expression may be passed from classical C++ code into
289	    // a quantum kernel. It is therefore natural to allow the lambda expression
290	    // to use quantum types.
291	    quantumTypesNotAllowed = false;
292	    auto result = Base::TraverseLambdaExpr(x);
293	    quantumTypesNotAllowed = saveQuantumTypesNotAllowed;
294	    return result;
295	  }
296	
297	  bool VisitLambdaExpr(clang::LambdaExpr *lambda) {
298	    if (ignoreTemplate)
299	      return true;
300	    if (const auto *cxxMethodDecl = lambda->getCallOperator())
301	      if (const auto *f = cxxMethodDecl->getAsFunction()->getDefinition())
302	        if (cudaq::ASTBridgeAction::ASTBridgeConsumer::isQuantum(f))
303	          processQpu(cudaq::detail::getTagNameOfFunctionDecl(f, mangler), f);
304	    return true;
305	  }
306	
307	  // Ignore the body of a template that has not been instantiated.
308	  bool TraverseClassTemplateDecl(clang::ClassTemplateDecl *x) {
309	    ignoreTemplate = true;
310	    auto result = Base::TraverseClassTemplateDecl(x);
311	    ignoreTemplate = false;
312	    return result;
313	  }
314	
315	  // Process the body of an instantiated template.
316	  bool TraverseClassTemplateSpecializationDecl(
317	      clang::ClassTemplateSpecializationDecl *x) {
318	    bool saveIgnoreTemplate = ignoreTemplate;
319	    ignoreTemplate = false;
320	    auto result = Base::TraverseClassTemplateSpecializationDecl(x);
321	    ignoreTemplate = saveIgnoreTemplate;
322	    return result;
323	  }
324	
325	  // For a function template, skip the template declaration and traverse the
326	  // instantiations of the template function instead.
327	  bool TraverseFunctionTemplateDecl(clang::FunctionTemplateDecl *x) {
328	    if (x == x->getCanonicalDecl())
329	      if (!TraverseTemplateInstantiations(x))
330	        return false;
331	    return true;
332	  }
333	
334	  bool isTupleReverseVar(clang::VarDecl *decl) {
335	    if (cudaq::isInNamespace(decl, "cudaq"))
336	      return decl->getName() == "TupleIsReverse";
337	    return false;
338	  }
339	
340	  bool VisitVarDecl(clang::VarDecl *x) {
341	    if (isTupleReverseVar(x)) {
342	      auto opt =
343	          x->getAnyInitializer()->getIntegerConstantExpr(x->getASTContext());
344	      if (opt) {
345	        LLVM_DEBUG(llvm::dbgs() << "tuples are reversed: " << *opt << '\n');
346	        tuplesAreReversed = !opt->isZero();
347	      }
348	    }
349	    if (cudaq::isInNamespace(x, "cudaq") && cudaq::isInNamespace(x, "detail") &&
350	        x->getName() == "_nvqpp_sizeof") {
351	      // This constexpr is the sizeof a pauli_word and a std::string.
352	      auto opt =
353	          x->getAnyInitializer()->getIntegerConstantExpr(x->getASTContext());
354	      assert(opt && "must compute the sizeof a cudaq::pauli_word");
355	      auto sizeofString = opt->getZExtValue();
356	      auto sizeAttr = module->getAttr(cudaq::runtime::sizeofStringAttrName);
357	      if (sizeAttr) {
358	        assert(sizeofString == cast<IntegerAttr>(sizeAttr).getUInt());
359	      } else {
360	        auto *ctx = module.getContext();
361	        auto i64Ty = IntegerType::get(ctx, 64);
362	        module->setAttr(cudaq::runtime::sizeofStringAttrName,
363	                        IntegerAttr::get(i64Ty, sizeofString));
364	      }
365	    }
366	    // The check to make sure that quantum data types are only used in kernels
367	    // is done here. This checks both variable declarations and parameters.
368	    if (quantumTypesNotAllowed)
369	      if (auto *ty = x->getType().getTypePtr())
370	        if (auto *decl = ty->getAsCXXRecordDecl();
371	            decl && cudaq::isInNamespace(decl, "cudaq"))
372	          if (auto *id = decl->getIdentifier()) {
373	            auto name = id->getName();
374	            if (name == "qubit" || name == "qudit" || name == "qspan" ||
375	                name.starts_with("qreg") || name.starts_with("qvector") ||
376	                name.starts_with("qarray") || name.starts_with("qview"))
377	              cudaq::detail::reportClangError(
378	                  x, mangler,
379	                  "may not use quantum types in non-kernel functions");
380	          }
381	    return true;
382	  }
383	
384	  bool isTupleReversed() const { return tuplesAreReversed; }
385	
386	private:
387	  cudaq::EmittedFunctionsCollection &functionsToEmit;
388	  clang::CallGraph &callGraphBuilder;
389	  clang::ItaniumMangleContext *mangler;
390	  ModuleOp module;
391	  std::unordered_map<std::string, std::string> &customOperationNames;
392	  // A class that is being visited. Need to run semantics checks on it if and
393	  // only if it has a quantum kernel.
394	  const clang::CXXRecordDecl *checkedClass = nullptr;
395	  bool ignoreTemplate = false;
396	  bool quantumTypesNotAllowed = false;
397	  bool tuplesAreReversed = false;
398	};
