418	Value QuakeBridgeVisitor::popValue() {
419	  Value result = peekValue();
420	  LLVM_DEBUG(
421	      llvm::dbgs() << std::string(valueStack.size() - 1, ' ') << "-pop value: ";
422	      auto *defOp = result.getDefiningOp();
423	      if (debugOpNameOnly && defOp) llvm::dbgs() << defOp->getName() << '\n';
