442	bool QuakeBridgeVisitor::generateFunctionDeclaration(
443	    StringRef funcName, const clang::FunctionDecl *x) {
444	  allowUnknownRecordType = true;
445	  if (!TraverseType(x->getType())) {
446	    reportClangError(x, mangler, "failed to generate type for kernel function");
447	    typeStack.clear();
448	    return false;
449	  }
450	  allowUnknownRecordType = false;
451	  if (!doSyntaxChecks(x))
452	    return false;
453	  auto funcTy = cast<FunctionType>(popType());
454	  auto loc = toLocation(x);
455	  [[maybe_unused]] auto fnPair = getOrAddFunc(loc, funcName, funcTy);
456	  assert(fnPair.first && "expected FuncOp to be created");
457	  if (!isa<clang::CXXMethodDecl>(x) || x->isStatic())
458	    fnPair.first->setAttr("no_this", builder.getUnitAttr());
459	  assert(typeStack.empty() && "expected type stack to be cleared");
460	  // Retain the attribute for custom operation generator functions
461	  if (cudaq::ASTBridgeAction::ASTBridgeConsumer::isCustomOpGenerator(x))
462	    fnPair.first->setAttr(cudaq::generatorAnnotation, builder.getUnitAttr());
463	  return true;
464	}
