505	static bool isX86_64(clang::ASTContext &astContext) {
506	  return astContext.getTargetInfo().getTriple().getArch() ==
507	         llvm::Triple::x86_64;
508	}
509	
510	void ASTBridgeAction::ASTBridgeConsumer::addFunctionDecl(
511	    const clang::FunctionDecl *funcDecl, detail::QuakeBridgeVisitor &visitor,
512	    FunctionType funcTy, StringRef devFuncName, bool isDecl) {
513	  auto funcName = visitor.cxxMangledDeclName(funcDecl);
514	  if (module->lookupSymbol(funcName))
515	    return;
516	  auto loc = toSourceLocation(module->getContext(), &astContext,
517	                              funcDecl->getSourceRange());
518	  auto devFuncTy =
519	      module->lookupSymbol<func::FuncOp>(devFuncName).getFunctionType();
520	  OpBuilder build(module->getBodyRegion());
521	  OpBuilder::InsertionGuard guard(build);
522	  build.setInsertionPointToEnd(module->getBody());
523	  bool addThisPtr =
524	      isa<clang::CXXMethodDecl>(funcDecl) && !funcDecl->isStatic();
525	  FunctionType hostFuncTy =
526	      opt::factory::toHostSideFuncType(funcTy, addThisPtr, *module);
527	  auto func = func::FuncOp::create(build, loc, funcName, hostFuncTy,
528	                                   ArrayRef<NamedAttribute>{});
529	  if (!addThisPtr)
530	    func->setAttr("no_this", build.getUnitAttr());
531	
532	  if (isDecl) {
533	    func.setPrivate();
534	  } else {
535	    func.setPublic();
536	    // Create a dummy implementation for the host-side function. This is so that
537	    // MLIR's restriction on "public" visibility is met and MLIR does not remove
538	    // the declaration before we can autogenerate the code in a later pass.
539	    auto *block = func.addEntryBlock();
540	    build.setInsertionPointToStart(block);
541	    SmallVector<Value> results;
542	    for (auto resTy : hostFuncTy.getResults())
543	      results.push_back(cc::UndefOp::create(build, loc, resTy));
544	    func::ReturnOp::create(build, loc, results);
545	  }
546	
547	  // Walk the arguments and add byval attributes where needed.
548	  assert(visitor.isItaniumCXXABI() && "Microsoft ABI not implemented");
549	  auto hiddenSRet = opt::factory::hasHiddenSRet(devFuncTy);
550	  auto delta = cc::numberOfHiddenArgs(addThisPtr, hiddenSRet);
551	  if (hiddenSRet) {
552	    // The first argument should be a pointer type if this function has a hidden
553	    // sret.
554	    if (auto ptrTy = dyn_cast<cc::PointerType>(hostFuncTy.getInput(0))) {
555	      auto eleTy = ptrTy.getElementType();
556	      assert(isa<cc::StructType>(eleTy) && "must be a struct");
557	      func.setArgAttr(0, LLVM::LLVMDialect::getStructRetAttrName(),
558	                      TypeAttr::get(eleTy));
559	    }
560	  }
561	
562	  // Pass over the parameters and add a byval attribute where required.
563	  for (auto iter : llvm::enumerate(funcDecl->parameters())) {
564	    auto *paramDecl = iter.value();
565	    // See clang::CodeGen::TargetInfo::getRecordArgABI()
566	    auto paramType = paramDecl->getType();
567	    if (auto *recTy = paramType->getAs<clang::RecordType>()) {
568	      auto *d = recTy->getDecl();
569	      if (isa<clang::CXXRecordDecl>(d)) {
570	        // On x86_64, canPassInRegisters() returning true corresponds to
571	        // RAA_Default, which means the compiler should use "normal C aggregate
572	        // rules". Therefore, this struct type value is passed using a pointer
573	        // and the byval attribute. Otherwise, the compiler will pass by an
574	        // indirection (pointer), omit the byval attribute, and skip making
575	        // copies, etc.
576	        // On aarch64, the convention is to omit the byval attribute.
577	        if (d->canPassInRegisters() && isX86_64(astContext)) {
578	          auto idx = iter.index();
579	          auto argPos = idx + delta;
580	          if (auto ptrTy =
581	                  dyn_cast<cc::PointerType>(hostFuncTy.getInput(argPos))) {
582	            auto strTy = ptrTy.getElementType();
583	            assert(isa<cc::StructType>(strTy) && "must be a struct");
584	            func.setArgAttr(argPos, LLVM::LLVMDialect::getByValAttrName(),
585	                            TypeAttr::get(strTy));
586	          } else if (opt::factory::structUsesTwoArguments(
587	                         funcTy.getInput(idx))) {
588	            // On x86_64, we may pass the struct as 2 distinct arguments. We
589	            // must adjust the offset on the fly.
590	            ++delta;
591	          }
592	        }
593	      }
594	    }
595	  }
596	}
597	
598	void ASTBridgeAction::ASTBridgeConsumer::HandleTranslationUnit(
599	    clang::ASTContext &astContext) {
600	  // First make sure there are no syntax errors, etc.
601	  auto &de = astContext.getDiagnostics();
602	  auto errorCount = de.getClient()->getNumErrors();
603	  if (errorCount != 0) {
604	    auto id =
605	        de.getCustomDiagID(clang::DiagnosticsEngine::Error,
606	                           "C++ source has errors. nvq++ cannot proceed.");
607	    de.Report(id);
608	    std::exit(1);
609	  }
610	
611	  // If no errors, then proceed to lowering the kernels.
612	  llvm::SmallVector<clang::Decl *> reachableFuncs =
613	      listReachableFunctions(callGraphBuilder.getRoot());
614	  auto *ctx = module->getContext();
615	  detail::QuakeBridgeVisitor visitor(
616	      &astContext, ctx, builder, module.get(), symbol_table, functionsToEmit,
617	      reachableFuncs, cxx_mangled_kernel_names, ci, mangler,
618	      customOperationNames, allocator, tuplesAreReversed);
619	
620	  // First generate declarations for all kernels.
621	  bool ok = true;
622	  for (auto fdPair : functionsToEmit) {
623	    std::string entryName = visitor.generateCudaqKernelName(fdPair);
624	    ok &= visitor.generateFunctionDeclaration(entryName, fdPair.second);
625	  }
626	  if (!ok) {
627	    // Syntax errors: stop processing the kernels.
628	    return;
629	  }
630	
631	  // Now lower each kernel function definition.
632	  for (auto fdPair : functionsToEmit) {
633	    SymbolTableScope var_scope(symbol_table);
634	    std::string entryName = visitor.generateCudaqKernelName(fdPair);
635	    visitor.setEntryName(entryName);
636	    // Extend the mangled kernel names map.
637	    auto mangledFuncName = visitor.cxxMangledDeclName(fdPair.second);
638	    cxx_mangled_kernel_names.insert({entryName, mangledFuncName});
639	    LLVM_DEBUG(llvm::dbgs() << "lowering function: " << entryName << '\n');
640	    visitor.resetNextTopLevelFunction();
641	    visitor.TraverseDecl(const_cast<clang::FunctionDecl *>(fdPair.second));
642	    if (auto func = module->lookupSymbol<func::FuncOp>(entryName)) {
643	      // Rationale: If a function marked as quantum code takes or returns
644	      // qubits or measurement "handles", then it must be a pure quantum kernel
645	      // that can only be called from other quantum code and never from
646	      // classical code. Conversely, a kernel that is called from a quantum
647	      // kernel entry function must (for now) take or return qubits in order to
648	      // be stitched into the same circuit with the calling function. CUDA-Q
649	      // does not presently support a quantum circuit that invokes a separable
650	      // quantum circuit. Launching a quantum circuit implies exactly one
651	      // distinct circuit will be mapped to and execute on the QPU.
652	      auto unitAttr = UnitAttr::get(ctx);
653	      // Flag func as a quantum kernel.
654	      func->setAttr(kernelAttrName, unitAttr);
655	      bool hasDeviceOnlyTypes =
656	          hasAnyQuakeOrHandleTypes(func.getFunctionType());
657	      if (hasDeviceOnlyTypes)
658	        if (auto *md = dyn_cast<clang::CXXMethodDecl>(fdPair.second);
659	            md && md->getOverloadedOperator() == clang::OO_Call) {
660	          // Functor `operator()` with a handle in the signature is the only
661	          // entry-point shape we can disambiguate from a free `__qpu__`
662	          // function at AST time, so diagnose it explicitly here. Free
663	          // functions silently demote to the device-only worklist below.
664	          if (containsHandleInSignature(func.getFunctionType())) {
665	            cudaq::detail::reportClangError(
666	                fdPair.second, mangler,
667	                "measurement handle cannot cross the host-device boundary; "
668	                "entry-point kernels must discriminate first");
669	            continue;
670	          }
671	        }
672	      if (!hasDeviceOnlyTypes &&
673	          (!cudaq::ASTBridgeAction::ASTBridgeConsumer::isCustomOpGenerator(
674	              fdPair.second))) {
675	        // Flag func as an entry point to a quantum kernel.
676	        func->setAttr(entryPointAttrName, unitAttr);
677	        // Generate a declaration for the CPU C++ function.
678	        addFunctionDecl(fdPair.second, visitor, func.getFunctionType(),
679	                        entryName, func.empty());
680	      }
681	    }
682	  }
683	
684	  // Not a kernel or entry point, but part of the call graph.
685	  if (LOWERING_TRANSITIVE_CLOSURE) {
686	    for (auto *rfp : reachableFuncs) {
687	      if (clang::isa<clang::CXXConstructorDecl>(rfp))
688	        continue;
689	
690	      if (auto *rf = dyn_cast<clang::FunctionDecl>(rfp)) {
691	        if (rf->getBody()) {
692	          SymbolTableScope var_scope(symbol_table);
693	          // Create the function and set the builder.
694	          auto mangledFuncName = visitor.cxxMangledDeclName(rf);
695	          visitor.setCurrentFunctionName(mangledFuncName);
696	          // FIXME: lower these classical compute functions to CC.
697	          visitor.TraverseDecl(rf);
698	        }
699	      }
700	    }
701	  }
702	}
703	
704	bool ASTBridgeAction::ASTBridgeConsumer::HandleTopLevelDecl(
705	    clang::DeclGroupRef dg) {
706	  QPUCodeFinder finder(functionsToEmit, callGraphBuilder, mangler, module.get(),
707	                       customOperationNames);
708	  // Loop over all decls, saving the function decls that are quantum kernels.
709	  for (const auto *decl : dg)
710	    finder.TraverseDecl(const_cast<clang::Decl *>(decl));
711	  tuplesAreReversed |= finder.isTupleReversed();
712	  return true;
713	}
714	
715	Location toSourceLocation(MLIRContext *ctx, clang::ASTContext *astCtx,
716	                          const clang::SourceRange &srcRange) {
717	  auto &srcMgr = astCtx->getSourceManager();
718	  auto srcLoc = srcRange.getBegin();
719	  auto spellingLoc = srcMgr.getSpellingLoc(srcLoc);
720	  auto line = srcMgr.getSpellingLineNumber(spellingLoc);
721	  auto column = srcMgr.getSpellingColumnNumber(spellingLoc);
722	  auto file = srcMgr.getFilename(spellingLoc);
723	  return FileLineColLoc::get(ctx, file, line, column);
724	}
725	
726	// Determine if this global has `extern "C"` linkage.
727	bool isInExternC(const clang::GlobalDecl &x) {
728	  if (auto *funcDecl = dyn_cast<clang::FunctionDecl>(x.getDecl()))
729	    return funcDecl->isExternC();
730	  if (auto *varDecl = dyn_cast<clang::VarDecl>(x.getDecl()))
731	    return varDecl->isExternC();
732	  return false;
733	}
734	
735	} // namespace cudaq
736	
737	namespace cudaq::detail {
738	
739	std::string getCxxMangledTypeName(clang::QualType ty,
740	                                  clang::ItaniumMangleContext *mangler) {
741	  std::string s;
742	  llvm::raw_string_ostream os(s);
743	  mangler->mangleCanonicalTypeName(ty, os);
744	  os.flush();
745	  LLVM_DEBUG(llvm::dbgs() << "type name mangled as '" << s << "'\n");
746	  return s;
747	}
748	
749	std::string getCxxMangledDeclName(clang::GlobalDecl decl,
750	                                  clang::ItaniumMangleContext *mangler) {
751	  if (isInExternC(decl)) {
752	    if (auto *funcDecl = dyn_cast<clang::FunctionDecl>(decl.getDecl()))
753	      return funcDecl->getName().str();
754	    reportClangError(decl.getDecl(), mangler, "unexpected global");
755	  }
756	  std::string s;
757	  llvm::raw_string_ostream os(s);
758	  mangler->mangleCXXName(decl, os);
759	  os.flush();
760	  return s;
761	}
