  // Check and see if this quantum operation is adjoint
  bool isAdjoint = false;
  bool isControl = false;
  auto *functionDecl = x->getCalleeDecl()->getAsFunction();
  if (auto *templateArgs = functionDecl->getTemplateSpecializationArgs())
    if (templateArgs->size() > 0) {
      auto gateModifierArg = templateArgs->asArray()[0];
      if (gateModifierArg.getKind() == clang::TemplateArgument::ArgKind::Type)
        if (auto *structTy =
                gateModifierArg.getAsType()->getAsStructureType())
          if (auto structTypeAsRecord = structTy->getAsCXXRecordDecl()) {
            isAdjoint = structTypeAsRecord->getName() == "adj";
            isControl = structTypeAsRecord->getName() == "ctrl";
          }
    }

  if (funcName == "exp_pauli") {
    assert(args.size() > 2);
    SmallVector<Value> parameters;
    SmallVector<Value> targets;
    Value pauliWord;
    auto addTheString = [&](Value v) {
      // The C-string argument (char*) may be loaded by an lvalue to rvalue
      // cast. Here, we must pass the pointer and not the first character's
      // value.
      if (isCharPointerType(v.getType())) {
        pauliWord = v;
      } else if (auto load = v.getDefiningOp<cudaq::cc::LoadOp>()) {
        pauliWord = load.getPtrvalue();
      } else if (isCharspanPointerType(v.getType())) {
        // Load the char span, which is a char*
        auto span = cc::LoadOp::create(builder, loc, v);
        pauliWord = span;
      } else if (isa<cudaq::cc::CharspanType>(v.getType())) {
        pauliWord = v;
      } else {
        reportClangError(x, mangler, "could not determine string argument");
      }
    };
    if (args.size() == 3 && isa<cudaq::quake::VeqType>(args[1].getType())) {
      // Have f64, veq, string
      parameters.push_back(args[0]);
      targets.push_back(args[1]);
      addTheString(args[2]);
    } else {
      // should have f64, string, qubits...
      // need f64, veq, string, so process here

      // add f64 value
      parameters.push_back(args[0]);

      // concat the qubits to a veq
      SmallVector<Value> quantumArgs;
      for (std::size_t i = 2; i < args.size(); i++)
        quantumArgs.push_back(args[i]);
      targets.push_back(cudaq::quake::ConcatOp::create(
          builder, loc,
          cudaq::quake::VeqType::get(builder.getContext(),
                                     quantumArgs.size()),
          quantumArgs));
      addTheString(args[1]);
    }

    cudaq::quake::ExpPauliOp::create(builder, loc, parameters, ValueRange{},
                                     targets, pauliWord);
    return true;
  }

  if (funcName == "apply_noise") {
    SmallVector<Value> params;
    SmallVector<Value> qubits;
    bool inParams = true;
    for (auto iter : llvm::enumerate(args)) {
      auto a = iter.value();
      Type aTy = a.getType();
      if (inParams) {
        if (auto ptrTy = dyn_cast<cudaq::cc::PointerType>(aTy))
          if (isa<FloatType>(ptrTy.getElementType())) {
            params.push_back(a);
            continue;
          }
        if (auto stdvecTy = dyn_cast<cudaq::cc::StdvecType>(aTy))
          if (stdvecTy.getElementType() == builder.getF64Type() &&
              iter.index() == 0) {
            params.push_back(a);
            inParams = false;
            continue;
          }
        inParams = false;
      }
      // The first argument that is not floating-point must be a qubit. If
      // the user has interleaved floating-point and qubit arguments, that's
      // an error.
      if (isa<cudaq::quake::RefType, cudaq::quake::VeqType>(aTy)) {
        qubits.push_back(a);
      } else {
        reportClangError(x, mangler,
                         "apply_noise argument types not supported.");
        return false;
      }
    }

    if (auto callee = calleeOp.getDefiningOp<func::ConstantOp>()) {
      StringRef calleeName = callee.getValue();
      cudaq::quake::ApplyNoiseOp::create(builder, loc, calleeName, params,
                                         qubits);

      // Add the declaration of the function to the module.
      SmallVector<Type> argTys;
      for (auto p : params)
        argTys.push_back(p.getType());
      for (auto q : qubits)
        argTys.push_back(q.getType());
      auto calleeTy = FunctionType::get(builder.getContext(), argTys, {});
      cudaq::opt::factory::getOrAddFunc(loc, calleeName, calleeTy, module);
      return true;
    }

    reportClangError(x, mangler,
                     "apply_noise with a vector argument is deprecated.");
    return false;
  }

  if (funcName == "mx" || funcName == "my" || funcName == "mz") {
    // Measurements emit `quake.{mz,mx,my}` producing `!cc.measure_handle`
    // (scalar) or `!cc.stdvec<!cc.measure_handle>` (multi-qubit). The
    // bridge does not inline `quake.discriminate` at the call site;
    // discrimination happens later, only when a downstream coercion site
    // demands it.
    bool useStdvec =
        (args.size() > 1) ||
        (args.size() == 1 && isa<cudaq::quake::VeqType>(args[0].getType()));
    Type measTy = cc::MeasureHandleType::get(builder.getContext());
    if (useStdvec)
      measTy = cc::StdvecType::get(measTy);
    if (funcName == "mx")
      return pushValue(cudaq::quake::MxOp::create(builder, loc, measTy, args)
                           .getMeasOut());
    if (funcName == "my")
      return pushValue(cudaq::quake::MyOp::create(builder, loc, measTy, args)
                           .getMeasOut());
    return pushValue(
        cudaq::quake::MzOp::create(builder, loc, measTy, args).getMeasOut());
  }

  if (funcName == "to_bools") {
    // `cudaq::to_bools(std::vector<cudaq::measure_handle>)` is the bulk
    // counterpart to `measure_handle::operator bool()`. Lower to a
    // vectorized `quake.discriminate` on the handle vector. The stdvec
    // shape is fixed by the C++ overload resolution (clang would reject
    // any other argument type before the bridge sees the call), so the
    // dyn_cast is a sanity check, not a user-facing path.
    Value handleArg = loadHandleVectorIfPointer(builder, loc, args[0]);
    auto sv = dyn_cast<cc::StdvecType>(handleArg.getType());
    assert(sv && isa<cc::MeasureHandleType>(sv.getElementType()) &&
           "`cudaq::to_bools` always sees `!cc.stdvec<!cc.measure_handle>` "
           "after C++ overload resolution");
    auto resTy = cc::StdvecType::get(builder.getI1Type());
    return pushValue(
        cudaq::quake::DiscriminateOp::create(builder, loc, resTy, handleArg));
  }

  // Handle the quantum gate set.
  auto reportNegateError = [&]() {
    reportClangError(x, mangler, "target qubit cannot be negated");
  };
  if (funcName == "h")
    return buildOp<cudaq::quake::HOp>(builder, loc, args, negations,
                                      reportNegateError, /*adjoint=*/false,
                                      isControl);
  if (funcName == "ch")
    return buildOp<cudaq::quake::HOp>(builder, loc, args, negations,
                                      reportNegateError, /*adjoint=*/false,
                                      /*control=*/true);
  if (funcName == "x")
    return buildOp<cudaq::quake::XOp>(builder, loc, args, negations,
                                      reportNegateError, /*adjoint=*/false,
                                      isControl);
  if (funcName == "cnot" || funcName == "cx" || funcName == "ccx")
    return buildOp<cudaq::quake::XOp>(builder, loc, args, negations,
                                      reportNegateError, /*adjoint=*/false,
                                      /*control=*/true);
  if (funcName == "y")
    return buildOp<cudaq::quake::YOp>(builder, loc, args, negations,
                                      reportNegateError, /*adjoint=*/false,
                                      isControl);
  if (funcName == "cy")
    return buildOp<cudaq::quake::YOp>(builder, loc, args, negations,
                                      reportNegateError, /*adjoint=*/false,
                                      /*control=*/true);
  if (funcName == "z")
    return buildOp<cudaq::quake::ZOp>(builder, loc, args, negations,
                                      reportNegateError, /*adjoint=*/false,
                                      isControl);

