361	bool QuakeBridgeVisitor::TraverseFunctionDecl(clang::FunctionDecl *x) {
362	  // If we're already generating code (this FunctionDecl is nested), we only
363	  // traverse the type, adding the function type to the type stack.
364	  if (builder.getBlock()) {
365	    if (!TraverseType(x->getType()))
366	      return false;
367	    return WalkUpFromFunctionDecl(x);
368	  }
369	
370	  // If function is not on the list to be lowered, skip it.
371	  if (!needToLowerFunction(x))
372	    return true;
373	  // If this function is a function template and not the specialization of the
374	  // function template, we skip it. We only want to lower template functions
375	  // that have their types resolved.
376	  if (x->getDescribedFunctionTemplate() &&
377	      !x->isFunctionTemplateSpecialization())
378	    return true;
379	
380	  LLVM_DEBUG(llvm::dbgs() << "found function to lower: "
381	                          << x->getQualifiedNameAsString() << '\n');
382	
383	  // The following is copied/expanded from RecursiveASTVisitor, especially
384	  // TraverseFunctionHelper(), since we can't call, override, or customize
385	  // private methods.
386	  for (unsigned i = 0; i < x->getNumTemplateParameterLists(); ++i) {
387	    if (auto *TPL = x->getTemplateParameterList(i)) {
388	      for (auto *D : *TPL)
389	        if (!TraverseDecl(D))
390	          return false;
391	      if (auto *requiresClause = TPL->getRequiresClause())
392	        if (!TraverseStmt(requiresClause))
393	          return false;
394	    }
395	  }
396	  if (!TraverseNestedNameSpecifierLoc(x->getQualifierLoc()))
397	    return false;
398	  if (!TraverseDeclarationNameInfo(x->getNameInfo()))
399	    return false;
400	
401	  // If we're an explicit template specialization, iterate over the template
402	  // args that were explicitly specified.  If we were doing this in typing
403	  // order, we'd do it between the return type and the function args, but both
404	  // are handled by the FunctionTypeLoc above, so we have to choose one side.
405	  // I've decided to do before.
406	  if (const auto *FTSI = x->getTemplateSpecializationInfo()) {
407	    if (FTSI->getTemplateSpecializationKind() != clang::TSK_Undeclared &&
408	        FTSI->getTemplateSpecializationKind() !=
409	            clang::TSK_ImplicitInstantiation) {
410	      // A specialization might not have explicit template arguments if it has a
411	      // templated return type and concrete arguments.
412	      if (const auto *tali = FTSI->TemplateArgumentsAsWritten) {
413	        auto *tal = tali->getTemplateArgs();
414	        for (unsigned i = 0; i != tali->NumTemplateArgs; ++i)
415	          if (!TraverseTemplateArgumentLoc(tal[i]))
416	            return false;
417	      }
418	    }
419	  }
420	
421	  // Traversing the typeloc data structure gives us the unresolved surface
422	  // syntax, so a decl like `auto fn(auto p)` won't have reified types.
423	  if (!TraverseType(x->getType()))
424	    return false;
425	
426	  // Customization here.
427	  // After we have the function's type and arguments, create the function and
428	  // set the builder, if and only if this is a top-level visit to a kernel. If
429	  // this is just a reference to a kernel, the lowering will happen at some
430	  // point during the visit to each kernel in the compilation unit. Any
431	  // referenced kernel should never naively be lowered in the context of the
432	  // kernel being visited that contains the reference.
433	  auto funcName = getCurrentFunctionName();
434	  auto loc = toLocation(x);
435	  if (funcName.empty())
436	    return true;
